package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetIgnoreEmptyLines() throws Exception {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set the expected result when calling getIgnoreEmptyLines()
        when(csvFormat.getIgnoreEmptyLines()).thenReturn(true);

        // Invoke the method using reflection
        boolean result = (boolean) CSVFormat.class.getDeclaredMethod("getIgnoreEmptyLines").invoke(csvFormat);

        // Verify the result
        assertEquals(true, result);
    }

}
